UPDATE STOCPRDT SET
	   CTRL_USER_ID = #{CTRL_USER_ID}
	 , EC_BUYER_CD  = (CASE WHEN (#{CTRL_BUYER_CD}, '0') = '0' THEN EC_BUYER_CD ELSE #{CTRL_BUYER_CD} END)
	 , EC_DEPT_CD   = (CASE WHEN (#{CTRL_DEPT_CD}, '0')  = '0' THEN EC_DEPT_CD  ELSE #{CTRL_DEPT_CD} END)
	 , MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND PR_SQ    = #{PR_SQ}

UPDATE STOCPRDT SET
	   DEL_DATE = SYSDATE
	 , DEL_USER_ID = #{ses.userId}
	 , DEL_FLAG = '1'
	 , DEL_RMK  = #{DEL_RMK}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND PR_SQ    = #{PR_SQ}
   AND CTRL_USER_ID IS NULL	-- 구매담당자 지정 이전, 미접수인 건만 삭제 가능

mapper.select:
SELECT PRDT.BUYER_CD , PRDT.PR_NUM , PRDT.ITEM_CD , PRDT.ITEM_DESC , PRDT.ITEM_SPEC , PRDT.PR_QT , PRDT.UNIT_CD , (PRDT.DUE_DATE, 'yyyyMMdd') AS DUE_DATE , PRDT.DELY_TO_CD , PRDT.DELY_TO_NM , PRDT.ATT_FILE_NUM ,(SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = #{ses.gateCd} AND UUID = PRDT.ATT_FILE_NUM AND DEL_FLAG = '0') AS ATT_FILE_CNT , PRDT.CTRL_CD ,(SELECT CTRL_NM FROM STOCBACO WHERE GATE_CD = PRDT.GATE_CD AND CTRL_CD = PRDT.CTRL_CD AND DEL_FLAG = '0') AS CTRL_NM ,(PRDT.ITEM_RMK) AS ITEM_RMK , PRDT.VENDOR_CD , LENGTH(PRDT.VENDOR_CD) - LENGTH(REPLACE(PRDT.VENDOR_CD,'{','')) AS VENDOR_CNT ,(CASE WHEN (LENGTH(PRDT.VENDOR_CD) - LENGTH(REPLACE(PRDT.VENDOR_CD,'{',''))) = 1 THEN JSON_VALUE(PRDT.VENDOR_CD, '$.VENDOR_NM') ELSE TO_CHAR(LENGTH(PRDT.VENDOR_CD) - LENGTH(REPLACE(PRDT.VENDOR_CD,'{',''))) END) AS VENDOR_NM , TO_CHAR(PRDT.PR_SQ) AS PR_SQ , PRDT.UNIT_PRC , PRDT.PR_AMT ,GETMKBRNAME(PRDT.GATE_CD, PRDT.PR_BUYER_CD, 'MK', PRDT.MAKER_CD) AS MAKER_NM , PRDT.MAKER_CD , PRDT.MAKER_PART_NO , PRDT.ORIGIN_CD , PRDT.ITEM_RMK , PRDT.VENDOR_CD , PRDT.PURCHASE_TYPE , PRDT.VENDOR_OPEN_TYPE , PRDT.SUBMIT_TYPE , PRDT.CTRL_CD , PRDT.CTRL_USER_ID , PRDT.RECEIPT_DATE ,(PRDT.REJECT_RMK) REJECT_RMK , PRDT.REJECT_DATE , PRDT.PO_REQ_DATE , PRDT.CN_DATE ,(PRDT.RECEIPT_FLAG , '0') RECEIPT_FLAG , PRDT.LAST_VENDOR_CD , PRDT.LAST_UNIT_PRC , PRDT.LAST_ITEM_AMT , PRDT.LAST_PO_NUM , PRDT.LAST_PO_SQ , PRDT.LAST_PO_FLAG , PRDT.LAST_PO_CUR , PRDT.MNT_SANGJU_YN , PRDT.CONSUMER_AMT , PRDT.FC_MNT_TERM , PRDT.CH_RATE , PRDT.DOIB_AMT , PRDT.MNT_RATE , PRDT.MNT_SDAY , PRDT.MNT_EDAY , PRDT.MNT_GUR_MONTH , PRDT.RT_INSP_PERIOD , PRDT.FALT_RC_TG_TIME , PRDT.CM_REQ_ID , PRDT.CM_REQ_DET_ID , PRDT.MULPUM_ID , PRDT.PR_BUYER_CD , PRDT.PR_DEPT_CD , PRDT.EC_BUYER_CD , PRDT.EC_DEPT_CD ,(CASE WHEN PRDT.PR_BUYER_CD = '공동' THEN '공동' ELSE getCustName(PRDT.GATE_CD, PRDT.PR_BUYER_CD) ||' '|| getDeptName(PRDT.GATE_CD, PRDT.PR_BUYER_CD, PRDT.PR_DEPT_CD, #{ses.langCd}) END) AS PR_BUYER_NM ,(SELECT ST.CUST_NM ||' '|| DP.DEPT_NM FROM STOCCUST ST JOIN STOCOGDP DP ON (ST.GATE_CD = DP.GATE_CD AND ST.CUST_CD = DP.BUYER_CD) WHERE DP.GATE_CD = PRDT.GATE_CD AND DP.BUYER_CD = PRDT.EC_BUYER_CD AND DP.DEPT_CD = PRDT.EC_DEPT_CD) AS EC_BUYER_NM , PRDT.CM_TYPE , PRDT.CM_REQ_DET_NM , PRDT.BZ_TIMELINE_SDAY , PRDT.BZ_TIMELINE_EDAY , PRDT.ACC_CD , PRDT.ACC_HNG_NM , PRDT.ACC_MOK_NM , PRDT.ACC_DET_NM , PRDT.BDGT_INFO , PRDT.MNT_AMT , PRDT.PAY_PERIOD_MTHD , PRDT.PAY_PERIOD_MTHD2 , TO_CHAR(PRDT.GISANIL,'YYYYMMDD') AS GISANIL , PRDT.PROJECT_CD , PRDT.PROJECT_SQ , PRDT.PROJECT_TYPE , PRDT.CONT_GROUND , PRDT.CONT_RMK , PRHD.CUR , PRDT.VAT_TYPE , PRDT.AMT_TYPE , PRHD.SIGN_STATUS ,GETCODENAME(#{ses.gateCd}, 'M020', PRHD.SIGN_STATUS, #{ses.langCd}) as SIGN_STATUS_NM ,(PRHD.REQ_DATE, 'yyyyMMdd') AS REQ_DATE ,GETUSERNAME(PRHD.GATE_CD, PRHD.REG_USER_ID, #{ses.langCd}) AS REQ_USER_NM , PRHD.SUBJECT ,(PRDT.RECEIPT_DATE, 'yyyyMMdd') AS RECEIPT_DATE ,GETUSERNAME(PRDT.GATE_CD, PRDT.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , PRDT.PROGRESS_CD , PRHD.REG_USER_ID ,(CASE WHEN (SELECT (MAX(DT.BID_CNT), '0') FROM STOCBDDT DT JOIN STOCBDHD HD ON (DT.GATE_CD = HD.GATE_CD AND DT.BUYER_CD = HD.BUYER_CD AND DT.BID_NUM = HD.BID_NUM AND DT.BID_CNT = HD.BID_CNT AND HD.DEL_FLAG = '0') WHERE DT.GATE_CD = PRDT.GATE_CD AND DT.PB_BUYER_CD = PRDT.BUYER_CD -- 빼먹으면 안됨 AND DT.PR_NUM = PRDT.PR_NUM AND DT.PR_SQ = PRDT.PR_SQ AND DT.DEL_FLAG = '0' AND HD.BID_STATUS NOT IN ('2330', '9999') -- 2021.07.06 : 취소공고확정도 제외 AND TO_NUMBER(HD.BID_STATUS) >= 2300) > 0 THEN 'N' ELSE 'Y' END) AS POSSIBLE_FLAG ,(CASE WHEN (SELECT (MAX(DT.RFX_CNT), '0') FROM STOCRQDT DT JOIN STOCRQHD HD ON (DT.GATE_CD = HD.GATE_CD AND DT.BUYER_CD = HD.BUYER_CD AND DT.RFX_NUM = HD.RFX_NUM AND DT.RFX_CNT = HD.RFX_CNT AND HD.DEL_FLAG = '0') WHERE DT.GATE_CD = PRDT.GATE_CD AND DT.PB_BUYER_CD = PRDT.BUYER_CD -- 빼먹으면 안됨 AND DT.PR_NUM = PRDT.PR_NUM AND DT.PR_SQ = PRDT.PR_SQ AND DT.DEL_FLAG = '0' AND HD.RFX_TYPE IN ('RFQ','RYQ','RPC','RCA') /** 견적, 견적(연단가), 수의시담 : RFI는 제외(=동시 진행 가능함), 부속합의 */ AND TO_NUMBER(HD.PROGRESS_CD) >= 2300) > 0 THEN 'N' ELSE 'Y' END) AS RFX_POSSIBLE_FLAG ,(SELECT (MAX(TO_NUMBER(PROGRESS_CD)), 0) FROM STOCPRDT WHERE GATE_CD = PRHD.GATE_CD AND BUYER_CD = PRHD.BUYER_CD AND PR_NUM = PRHD.PR_NUM AND DEL_FLAG = '0') AS MAX_PROGRESS_CD , PRHD.IF_TYPE -- 인터페이스 유형(NH0011) : ITA(농협중앙회), ITB(농협은행) ,(PRHD.PR_TYPE, '10') AS PR_TYPE -- 구매유형(=계약구분 : M134) : 10(신규), 20(변경), 30(연장) , PRDT.PRE_BUYER_CD , PRDT.PRE_CONT_NUM , PRDT.PRE_CONT_CNT , PRDT.CM_REQ_ID /*2021.05.25 : 이전계약번호에 대한 협력사 가져오기*/ , ECCT.CONT_DESC AS PRE_CONT_DESC , ECCT.VENDOR_CD AS PRE_VENDOR_CD , GETVENDORNAME(ECCT.GATE_CD, ECCT.VENDOR_CD, #{ses.langCd}) AS PRE_VENDOR_NM ,ECCT.VENDOR_PIC_USER_NM AS PRE_VENDOR_PIC_USER_NM ,ECCT.VENDOR_PIC_USER_EMAIL AS PRE_VENDOR_PIC_USER_EMAIL ,ECCT.VENDOR_PIC_USER_CELL_NUM AS PRE_VENDOR_PIC_USER_CELL_NUM , ECCT.CUR AS PRE_CUR , ECCT.VAT_TYPE AS PRE_VAT_TYPE , ECCT.AMT_TYPE AS PRE_AMT_TYPE ,(ECCT.CONT_AMT, '0') AS PRE_CONT_AMT , ECCT.DELAY_RMK AS PRE_DELAY_RMK , ECCT.DELAY_NUME_RATE AS PRE_DELAY_NUME_RATE , ECCT.DELAY_DENO_RATE AS PRE_DELAY_DENO_RATE , ECCT.STAMP_DUTY_FLAG AS PRE_STAMP_DUTY_FLAG ,(ECCT.STAMP_DUTY_AMT, '0') AS PRE_STAMP_DUTY_AMT , ECCT.AUTO_RENEW_FLAG AS PRE_AUTO_RENEW_FLAG , ECCT.CONT_RMK AS PRE_CONT_RMK FROM STOCPRHD PRHD JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = PRHD.GATE_CD AND PRDT.BUYER_CD = PRHD.BUYER_CD AND PRDT.PR_NUM = PRHD.PR_NUM AND PRDT.DEL_FLAG = '0') LEFT JOIN STOCECCT ECCT ON (ECCT.GATE_CD = PRDT.GATE_CD AND ECCT.BUYER_CD = PRDT.PRE_BUYER_CD AND ECCT.CONT_NUM = PRDT.PRE_CONT_NUM AND ECCT.CONT_CNT = PRDT.PRE_CONT_CNT) WHERE PRHD.GATE_CD = #{ses.gateCd} AND PRHD.SIGN_STATUS = 'E' AND PRHD.DEL_FLAG = '0' AND PRDT.EC_BUYER_CD = #{ses.companyCd} -- 체결고객사 AND PRDT.PROGRESS_CD < '2300' -- 접수대기(2100), 접수완료(2200) AND PRDT.CTRL_USER_ID IS NOT NULL
AND PRHD.REQ_DATE >= (#{REQ_FROM_DATE}) AND PRHD.REQ_DATE <= (#{REQ_TO_DATE})
AND UPPER(REPLACE(PRHD.SUBJECT, ' ', '')) LIKE '%' UPPER(REPLACE(#{PR_SUBJECT}, ' ', '')) '%'
AND UPPER(PRHD.PR_NUM) LIKE '%' UPPER(#{PR_NUM}) '%'
AND PRDT.PURCHASE_TYPE = #{PURCHASE_TYPE}
AND PRHD.REG_USER_ID = #{REQ_USER_ID}
AND PRHD.IF_TYPE = #{IF_TYPE}
AND PRDT.PR_BUYER_CD = #{PR_BUYER_CD}
AND PRDT.PR_DEPT_CD = #{PR_DEPT_CD}
AND (PRDT.RECEIPT_FLAG,'0') = #{RECEIPT_FLAG}
AND PRDT.CTRL_USER_ID = #{CTRL_USER_ID}
AND GETUSERNAME(PRDT.GATE_CD, PRDT.CTRL_USER_ID, #{ses.langCd}) LIKE '%' #{CTRL_USER_NM} '%'
AND PRDT.CM_REQ_ID LIKE '%' UPPER(#{CM_REQ_ID}) '%'
ORDER BY PRHD.REQ_DATE DESC , PRDT.PR_NUM DESC , PRDT.PR_SQ

