UPDATE STOCPRDT SET
	  MOD_DATE     = SYSDATE
	, MOD_USER_ID  = #{ses.userId}
	, PROGRESS_CD  = #{PROGRESS_CD}
	, RECEIPT_FLAG = '200'
	, RECEIPT_DATE = SYSDATE
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND PR_SQ    = #{PR_SQ}

UPDATE STOCPRDT SET
	  MOD_DATE     = SYSDATE
	, MOD_USER_ID  = #{ses.userId}
	, PROGRESS_CD  = #{PROGRESS_CD}
	, RECEIPT_FLAG = '100'
	, REJECT_RMK   = #{REJECT_RMK}
	, REJECT_DATE  = SYSDATE
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND PR_SQ    = #{PR_SQ}

UPDATE STOCPRHD SET
	 SIGN_STATUS = 'T'
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM = #{PR_NUM}
   AND (SELECT COUNT(*) FROM STOCPRDT
	   	 WHERE GATE_CD  = #{ses.gateCd}
	   	   AND BUYER_CD = #{BUYER_CD}
	   	   AND PR_NUM   = #{PR_NUM}
	   	   AND DEL_FLAG = '0') = (SELECT COUNT(*) FROM STOCPRDT
								   WHERE GATE_CD  = #{ses.gateCd}
								     AND BUYER_CD = #{BUYER_CD}
								     AND PR_NUM   = #{PR_NUM}
								     AND DEL_FLAG = '0'
								     AND PROGRESS_CD = '1200')

UPDATE STOCPRDT SET
	 CTRL_USER_ID = #{CTRL_USER_ID}
	,PROGRESS_CD = #{PROGRESS_CD}
	,MOD_DATE = SYSDATE
	,MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND PR_SQ    = #{PR_SQ}

